import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.CXrMbE71.js";const p=JSON.parse('{"title":"📖 关于本书 (About the Book)","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),n={name:"about.md"};function l(i,e,h,s,u,b){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="📖-关于本书-about-the-book" tabindex="-1">📖 关于本书 (About the Book) <a class="header-anchor" href="#📖-关于本书-about-the-book" aria-label="Permalink to &quot;📖 关于本书 (About the Book)&quot;">​</a></h1><h2 id="🎯-愿景与初衷" tabindex="-1">🎯 愿景与初衷 <a class="header-anchor" href="#🎯-愿景与初衷" aria-label="Permalink to &quot;🎯 愿景与初衷&quot;">​</a></h2><p>在 2026 年，AI Agent 已经彻底走出了“玩具”阶段，演变为下一代操作系统的核心基础设施。从多模态终端硬件到云端编排网络，中国涌现出了一大批世界级的模型厂商和技术架构。</p><p>然而，市面上缺乏一份真正深入底层的技术内参。大部分资料仅仅停留在“如何使用 Coze 拖拽出一个机器人”的层面。</p><p><strong>本书旨在填补这一空白。</strong></p><p>我们将目光聚焦于系统设计、底层协议（如 MCP）、通信架构和多模态整合，对标大厂系统设计规范，深度剖析 DeepSeek、字节跳动、阿里巴巴、腾讯、智谱 AI 等生态体系。希望这份参考指南能帮助下一代开发者跨越壁垒，构建出真正具备生产力的 Agent 架构。</p><h2 id="💡-我们为什么能做到" tabindex="-1">💡 我们为什么能做到？ <a class="header-anchor" href="#💡-我们为什么能做到" aria-label="Permalink to &quot;💡 我们为什么能做到？&quot;">​</a></h2><p>本书由开源社区深度共建。我们在追踪最前沿进展的同时，引入了类似 SWE-bench 等严苛的国际基准测试，剥离了营销词汇，为您呈现最硬核的技术真相。</p><h2 id="🤝-欢迎加入" tabindex="-1">🤝 欢迎加入 <a class="header-anchor" href="#🤝-欢迎加入" aria-label="Permalink to &quot;🤝 欢迎加入&quot;">​</a></h2><p>这个项目不是静态的，它将随着 AI 领域的爆炸性发展而持续演进。 如果您发现了新的架构模式、测试基准或底层协议，欢迎查阅我们的 <a href="https://github.com/Electricitysheep/2026-ai-agent-book/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">贡献指南</a> 并提交 Pull Request！</p><blockquote><p><em>The future belongs to those who build the underlying engines of intelligence.</em></p></blockquote>',11)])])}const d=t(n,[["render",l]]);export{p as __pageData,d as default};
